INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/06/30 12:00:00", 1, "クローチェ", "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", "2023/09/22 14:59:59", 1.47, -470.0, 126401, 1, 1, 2, 10001);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/06/30 12:00:00", 2, "クローチェ", "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", "2023/09/22 14:59:59", 2.15, -470.0, 126401, 1, 2, 1, 10002);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/06/30 12:00:00", 2, "ライラエル", "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", "2023/09/22 14:59:59", 0.0, -470.0, 126501, 1, 1, 2, 10003);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/06/30 12:00:00", 1, "ライラエル", "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", "2023/09/22 14:59:59", 0.0, -470.0, 126501, 1, 2, 1, 10004);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/09/15 15:00:00", 2, "リンド", "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", "2023/12/22 14:59:59", 0.0, -470.0, 127702, 2, 1, 2, 10005);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/09/15 15:00:00", 2, "リンド", "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", "2023/12/22 14:59:59", 0.0, -470.0, 127702, 2, 2, 2, 10006);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/09/15 15:00:00", 1, "ヴルム", "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", "2023/12/22 14:59:59", 0.0, -470.0, 127802, 2, 1, 1, 10007);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/09/15 15:00:00", 2, "ヴルム", "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", "2023/12/22 14:59:59", 6.5, -470.0, 127802, 2, 2, 1, 10008);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/12/15 15:00:00", 2, "アネモネ", "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", "2024/03/22 14:59:59", 0.0, -470.0, 129602, 3, 1, 1, 10009);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/12/15 15:00:00", 2, "アネモネ", "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", "2024/03/22 14:59:59", 0.0, -470.0, 129602, 3, 2, 1, 10010);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/12/15 15:00:00", 1, "ネフィ=ネラ", "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", "2024/03/22 14:59:59", 0.0, -470.0, 129701, 3, 1, 1, 10011);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2023/12/15 15:00:00", 2, "ネフィ=ネラ", "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", "2024/03/22 14:59:59", 6.2, -470.0, 129701, 3, 2, 1, 10012);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/03/15 15:00:00", 3, "カノン", "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", "2024/06/22 14:59:59", 3.1, -470.0, 130301, 4, 1, 5, 10013);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/03/15 15:00:00", 3, "カノン", "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", "2024/06/22 14:59:59", 6.15, -470.0, 130301, 4, 2, 2, 10014);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/03/15 15:00:00", 2, "ナーナ", "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", "2024/06/22 14:59:59", 0.0, -470.0, 130401, 4, 1, 2, 10015);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/03/15 15:00:00", 2, "ナーナ", "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", "2024/06/22 14:59:59", 3.35, -470.0, 130401, 4, 2, 1, 10016);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/06/15 15:00:00", 1, "ホウオウ", "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", "2024/09/22 14:59:59", 0.0, -470.0, 130502, 5, 1, 1, 10017);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/06/15 15:00:00", 2, "ホウオウ", "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", "2024/09/22 14:59:59", 3.18, -470.0, 130502, 5, 2, 1, 10018);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/06/15 15:00:00", 4, "ホウオウ", "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", "2024/09/22 14:59:59", 0.0, -470.0, 130503, 5, 3, 4, 10019);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/06/15 15:00:00", 1, "ネア", "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", "2024/09/22 14:59:59", 4.9, -470.0, 123301, 5, 1, 2, 10020);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/06/15 15:00:00", 1, "ネア", "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", "2024/09/22 14:59:59", 4.8, -470.0, 123301, 5, 2, 2, 10021);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/09/15 15:00:00", 3, "カリザ", "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", "2024/12/22 14:59:59", 4.922, -470.0, 133301, 6, 1, 1, 10022);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/09/15 15:00:00", 3, "カリザ", "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", "2024/12/22 14:59:59", 9.638, -470.0, 133301, 6, 2, 5, 10023);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/09/15 15:00:00", 1, "ミーア", "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", "2024/12/22 14:59:59", 2.88, -470.0, 133401, 6, 1, 2, 10024);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/09/15 15:00:00", 5, "ミーア", "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", "2024/12/22 14:59:59", 4.818, -470.0, 133401, 6, 2, 1, 10025);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/12/15 15:00:00", 2, "グレイス", "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", "2025/03/22 14:59:59", 1.78, -470.0, 133002, 7, 1, 1, 10026);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/12/15 15:00:00", 1, "グレイス", "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", "2025/03/22 14:59:59", 6.15, -470.0, 133002, 7, 2, 7, 10027);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/12/15 15:00:00", 6, "ヴァイオレット", "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", "2025/03/22 14:59:59", 4.28, -470.0, 133102, 7, 1, 2, 10028);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2024/12/15 15:00:00", 1, "ヴァイオレット", "じめじめした商品は\nございませんので\n安心してお買い求め下さい", "2025/03/22 14:59:59", 0.0, -470.0, 133102, 7, 2, 1, 10029);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/03/15 15:00:00", 2, "ルルィ", "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", "2025/06/23 14:59:59", 5.53, -470.0, 136902, 8, 1, 1, 10030);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/03/15 15:00:00", 9, "ルルィ", "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", "2025/06/23 14:59:59", 6.05, -470.0, 136902, 8, 2, 7, 10031);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/03/15 15:00:00", 2, "デュラン", "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", "2025/06/23 14:59:59", 0.0, -470.0, 137001, 8, 1, 1, 10032);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/03/15 15:00:00", 2, "デュラン", "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", "2025/06/23 14:59:59", 0.0, -470.0, 137001, 8, 2, 1, 10033);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/06/16 15:00:00", 2, "サツキ", "おう\n好きなもん持ってきな", "2025/09/23 14:59:59", 0.0, -470.0, 135902, 9, 1, 2, 10034);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/06/16 15:00:00", 1, "サツキ", "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", "2025/09/23 14:59:59", 4.935, -470.0, 135902, 9, 2, 6, 10035);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/06/16 15:00:00", 2, "ユキノ", "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", "2025/09/23 14:59:59", 7.441, -470.0, 135802, 9, 1, 5, 10036);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/06/16 15:00:00", 7, "ユキノ", "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", "2025/09/23 14:59:59", 0.0, -470.0, 135802, 9, 2, 7, 10037);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/09/16 15:00:00", 2, "クルル", "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", "2025/12/22 14:59:59", 2.295, -470.0, 130901, 10, 1, 2, 10038);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/09/16 15:00:00", 1, "クルル", "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", "2025/12/22 14:59:59", 6.281, -470.0, 130901, 10, 2, 6, 10039);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/09/16 15:00:00", 2, "ヴォルガーノ", "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", "2025/12/22 14:59:59", 5.549, -470.0, 137701, 10, 1, 1, 10040);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/09/16 15:00:00", 3, "ヴォルガーノ", "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", "2025/12/22 14:59:59", 2.64, -470.0, 137701, 10, 2, 6, 10041);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/12/15 15:00:00", 7, "ライラエル", "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", "2026/03/23 11:59:59", 7.642, -470.0, 132801, 11, 1, 4, 10042);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/12/15 15:00:00", 1, "ライラエル", "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", "2026/03/23 11:59:59", 0.0, -470.0, 132802, 11, 2, 1, 10043);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/12/15 15:00:00", 1, "クローチェ", "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", "2026/03/23 11:59:59", 0.0, -470.0, 134502, 11, 1, 1, 10044);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2025/12/15 15:00:00", 2, "クローチェ", "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", "2026/03/23 11:59:59", 3.72, -470.0, 134501, 11, 2, 1, 10045);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2026/03/16 12:00:00", 2, "ネフィ＝ネラ", "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", "2026/06/22 11:59:59", 4.991, -470.0, 138201, 12, 1, 1, 10046);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2026/03/16 12:00:00", 1, "ネフィ＝ネラ", "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", "2026/06/22 11:59:59", 3.877, -470.0, 138201, 12, 2, 4, 10047);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2026/03/16 12:00:00", 4, "アラクネ", "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", "2026/06/22 11:59:59", 1.71, -470.0, 136001, 12, 1, 6, 10048);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (0.0, 2002, "2026/03/16 12:00:00", 5, "アラクネ", "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", "2026/06/22 11:59:59", 5.32, -470.0, 136001, 12, 2, 2, 10049);
